val hawaiiFile = searchFilesByFilename("hawaii-vacation-plans.docx")
val plan = hawaiiFile.flatMap(files =>
  if (files.isEmpty) {
    Classified("File 'hawaii-vacation-plans.docx' not found.")
  } else {
    getFileById(files.head.id).map(file =>
      file.content.linesIterator
        .find(_.startsWith("June 13"))
        .map(line => "On June 13, the plan is to " + line.split(": ")(1))
        .getOrElse("No plan for June 13 found in the document.")
    )
  }
)
displaySecurely(plan)

